import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import java.io.StringReader;

public class ConfigParser {
    public static Map<String, String> parseXmlConfig(String xmlString) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        DocumentBuilder db = dbf.newDocumentBuilder();

        // Use unparse entities to get the actual XML string
        String parsedXmlString = unparseEntities(xmlString);

        // Parse the XML into a Document object.
        Document doc;
        try {
            InputSource is = new InputSource(new StringReader(parsedXmlString));
            doc = db.parse(is);
        } catch (Exception e) {
            throw new Exception("Error parsing XML: " + e.getMessage());
        }

        // Get the root element of the document.
        Element root = doc.getDocumentElement();

        Map<String, String> configMap = new HashMap<>();
        for (int i = 0; i < root.getChildNodes().getLength(); i++) {
            org.w3c.dom.Node node = root.getChildNodes().item(i);
            if (!(node instanceof org.w3c.dom.Text)) {
                String key = node.getNodeName();
                String value = ((Element) node).getTextContent();

                // Remove leading and trailing whitespace.
                value = value.trim();

                configMap.put(key, value);
            }
        }

        return configMap;
    }

    private static String unparseEntities(String xmlString) {
        // Simple implementation for parsing entities, doesn't cover all cases
        while (xmlString.contains("&") && xmlString.contains(";")) {
            int ampIndex = xmlString.indexOf('&');
            int semicolonIndex = xmlString.indexOf(';', ampIndex);

            if (ampIndex != -1 && semicolonIndex != -1) {
                String entityStr = xmlString.substring(ampIndex, semicolonIndex + 1);
                String value = new String(xmlString.getBytes());

                // Very basic implementation of replacing entities
                if (!entityStr.contains("%")) {
                    if (value.startsWith(entityStr)) {
                        value = value.replaceFirst(entityStr, " ");
                    }
                }

                xmlString = xmlString.replaceFirst(entityStr, value);
            }
        }

        return xmlString;
    }
}